func prettyPrint(prefix string, color string, text string) {
	currentTime := time.Now().Format("15:04:05")
	fmt.Printf("[\033[1;94m%s\033[0m] %s%s:\033[0m %s\n", currentTime, color, prefix, text)
	logs.WriteString(fmt.Sprintf("[%s] %s: %s\n", currentTime, prefix, text))
}

func printBar(done int32, total int, percent float64, elapsed string) {
	fmt.Fprintf(os.Stderr, "\033[1;38;2;140;140;255m%d/%d\033[0m targets scanned (\033[1;38;2;152;92;255m%.2f%%\033[0m). Elapsed: \033[1;38;2;92;220;255m%s\033[0m\r", done, total, percent, elapsed)
}

func log(text string) {
	prettyPrint("INFO", "\033[1;38;2;140;140;255m", text)
}

func logErr(text string) {
	prettyPrint("ERRO", "\033[1;38;2;255;90;90m", text)
}

func warn(text string) {
	prettyPrint("WARN", "\033[1;38;2;255;165;0m", text)
}

func logPortOpen(ip string) {
	prettyPrint("OPEN", "\033[1;38;2;90;255;90m", "Target "+ip+" is open")
}

func logCredentialsFound(ip string, credentials string) {
	prettyPrint("FOUN", "\033[1;38;2;0;255;160m", "Credentials for "+ip+" found! ("+credentials+")")
}

func logConnected(ip string) {
	prettyPrint("FOUN", "\033[1;38;2;0;255;160m", "Successfully connected to "+ip+" (no credentials)")
}

func incIP(ip net.IP) {
	for j := len(ip) - 1; j >= 0; j-- {
		ip[j]++
		if ip[j] > 0 {
			break
		}
	}
}

var path string
var results *os.File
var logs *os.File

func initDirectory() {
	path = "./results/" + time.Now().Format("2006-01-02-15-04") + "/"

	err := os.MkdirAll(path, 0755)
	if err != nil {
		warn("Error creating results directory: " + err.Error())
	}

	os.MkdirAll(path+"snapshots", 0755)
	logs, _ = os.Create(path + "logs.txt")
	results, _ = os.Create(path + "results.txt")

	logs.WriteString("LolScan \"" + Version + "\"\n")
	logs.WriteString("OS: " + runtime.GOOS + " " + runtime.GOARCH + "\n")

}

func addResult(service services.ServiceInterface, cred string) {
	logEntry := service.GetAddress() + " - " + cred + " (" + service.GetName() + ", " + service.GetType().String() + ")"

	if cred == "" {
		logEntry = service.GetAddress() + " (" + service.GetName() + ", " + service.GetType().String() + ")"
	}

	results.WriteString(logEntry + "\n")
}
